class Solution(object):
    def lemonadeChange(self, bills):
        five_count = ten_count = 0
        for bill in bills:
            if bill == 5:
                five_count += 1
            elif bill == 10:
                ten_count += 1
                five_count -= 1
            else:  # bill == 20
                if ten_count > 0:
                    ten_count -= 1
                    five_count -= 1
                else:
                    five_count -= 3
            if five_count < 0:
                return False
        return True
